// Manual sync
// ============================================================
async function doSync() {
  if (!scrapedData) return;
  syncBtn.disabled = true;
  setStatus('<span class="spinner"></span> Syncing...', 'loading');

  try {
    const manifest = chrome.runtime.getManifest();
    const payload = {
      name: scrapedData.name,
      team: teamSelect.value,
      source: 'extension',
